import { Accordion as AccordionRoot, type AccordionProps, type AccordionSingleProps, type AccordionMultipleProps } from "./accordion";
import { AccordionHeader, type AccordionHeaderProps } from "./accordion-header";
import { AccordionItem, type AccordionItemProps } from "./accordion-item";
import { AccordionTrigger, type AccordionTriggerProps } from "./accordion-trigger";
import { AccordionContent, type AccordionContentProps } from "./accordion-content";

const Accordion = Object.assign(AccordionRoot, {
  Header: AccordionHeader,
  Item: AccordionItem,
  Trigger: AccordionTrigger,
  Content: AccordionContent,
});

export { Accordion, type AccordionProps, type AccordionSingleProps, type AccordionMultipleProps };
export { AccordionHeader, type AccordionHeaderProps };
export { AccordionItem, type AccordionItemProps };
export { AccordionTrigger, type AccordionTriggerProps };
export { AccordionContent, type AccordionContentProps };

"use client";

import {
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  type Ref,
  useMemo,
  useRef,
} from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { AccordionContext } from "./accordion-context";
import { useAccordionState } from "./use-accordion-state";

export interface AccordionSingleProps {
  type?: "single";
  value?: string;
  onChange?: (value: string | undefined) => void;
  defaultValue?: string;
  collapsible?: boolean;
  children: ReactNode;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

export interface AccordionMultipleProps {
  type: "multiple";
  value?: string[];
  onChange?: (value: string[]) => void;
  defaultValue?: string[];
  children: ReactNode;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

export type AccordionProps = AccordionSingleProps | AccordionMultipleProps;

function AccordionRoot(props: AccordionProps) {
  const { ref, onKeyDown: externalOnKeyDown } = props;
  const { openValues, onToggle, collapsible } = useAccordionState(props);
  const containerRef = useRef<HTMLDivElement>(null);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "button",
    orientation: "vertical",
    wrap: true,
    moveFocus: true,
  });

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    externalOnKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  const contextValue = useMemo(
    () => ({ value: openValues, onToggle, collapsible }),
    [openValues, collapsible],
  );

  return (
    <AccordionContext value={contextValue}>
      <div
        ref={composeRefs(containerRef, ref)}
        role="group"
        className={cn("divide-y divide-border", props.className)}
        onKeyDown={handleKeyDown}
      >
        {props.children}
      </div>
    </AccordionContext>
  );
}

export { AccordionRoot as Accordion };

"use client";

import { createContext, useContext } from "react";

export interface AccordionContextValue {
  value: string[];
  onToggle: (itemValue: string) => void;
  collapsible: boolean;
}

export const AccordionContext = createContext<AccordionContextValue | undefined>(undefined);

export function useAccordionContext() {
  const context = useContext(AccordionContext);
  if (!context) {
    throw new Error("Accordion compound components must be used within Accordion");
  }
  return context;
}

export interface AccordionItemContextValue {
  value: string;
  isOpen: boolean;
  disabled: boolean;
  triggerId: string;
  contentId: string;
}

export const AccordionItemContext = createContext<AccordionItemContextValue | undefined>(undefined);

export function useAccordionItemContext() {
  const context = useContext(AccordionItemContext);
  if (!context) {
    throw new Error("AccordionTrigger/AccordionContent must be used within AccordionItem");
  }
  return context;
}

"use client";

import { type ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface AccordionHeaderProps {
  as?: "h2" | "h3" | "h4" | "h5" | "h6";
  children: ReactNode;
  className?: string;
}

export function AccordionHeader({ as: Tag = "h3", children, className }: AccordionHeaderProps) {
  return <Tag className={cn("m-0 font-normal", className)}>{children}</Tag>;
}

"use client";

import { useId, useMemo, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAccordionContext, AccordionItemContext } from "./accordion-context";

export interface AccordionItemProps {
  value: string;
  disabled?: boolean;
  children: ReactNode;
  className?: string;
}

export function AccordionItem({ value, disabled = false, children, className }: AccordionItemProps) {
  const { value: openValues } = useAccordionContext();
  const isOpen = openValues.includes(value);
  const itemId = useId();
  const triggerId = `${itemId}-trigger`;
  const contentId = `${itemId}-content`;

  const contextValue = useMemo(() => ({ value, isOpen, disabled, triggerId, contentId }), [value, isOpen, disabled, triggerId, contentId]);

  return (
    <AccordionItemContext value={contextValue}>
      <div className={cn("py-2", className)} data-state={isOpen ? "open" : "closed"} data-disabled={disabled || undefined}>
        {children}
      </div>
    </AccordionItemContext>
  );
}

"use client";

import { type ReactNode } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useAccordionContext, useAccordionItemContext } from "./accordion-context";

const triggerVariants = cva(
  "flex w-full items-center gap-2 font-mono text-muted-foreground hover:text-foreground transition-colors cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:text-muted-foreground focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      variant: {
        default: "text-sm",
        source: "text-xs mb-2",
      },
    },
    defaultVariants: { variant: "default" },
  }
);

export interface AccordionTriggerProps extends VariantProps<typeof triggerVariants> {
  children: ReactNode;
  className?: string;
  /** Custom handle element. Defaults to an animated Chevron. Pass `null` to hide. */
  handle?: ReactNode | null;
}

export function AccordionTrigger({ children, className, variant, handle }: AccordionTriggerProps) {
  const { onToggle, collapsible } = useAccordionContext();
  const { value, isOpen, disabled, triggerId, contentId } = useAccordionItemContext();

  const isDisabled = disabled || (!collapsible && isOpen);
  const resolvedHandle = handle === undefined ? <Chevron open={isOpen} size="sm" /> : handle;

  // role="button" is redundant on <button> but required: useNavigation queries [role="button"] as a CSS attribute selector
  return (
    <button
      type="button"
      role="button"
      id={triggerId}
      data-value={value}
      onClick={() => onToggle(value)}
      disabled={isDisabled}
      aria-expanded={isOpen}
      aria-controls={contentId}
      className={cn(triggerVariants({ variant }), className)}
    >
      {resolvedHandle}
      {children}
    </button>
  );
}

"use client";

import { type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAccordionItemContext } from "./accordion-context";

export interface AccordionContentProps {
  children: ReactNode;
  className?: string;
}

export function AccordionContent({ children, className }: AccordionContentProps) {
  const { isOpen, triggerId, contentId } = useAccordionItemContext();

  return (
    <div
      className={cn(
        "grid transition-[grid-template-rows] duration-200 ease-out",
        isOpen ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
      )}
      aria-hidden={!isOpen || undefined}
      inert={!isOpen || undefined}
    >
      <div
        className={cn("overflow-hidden min-h-0 pt-2", className)}
        role="region"
        id={contentId}
        aria-labelledby={triggerId}
      >
        {children}
      </div>
    </div>
  );
}

"use client";

import { useEffectEvent } from "react";
import {
  useControllableState,
  type UseControllableStateOptions,
} from "@/hooks/use-controllable-state";
import type { AccordionProps } from "./accordion";

function normalizeStateOptions(
  props: AccordionProps,
): UseControllableStateOptions<string[]> {
  if (props.type === "multiple") {
    return {
      value: props.value,
      defaultValue: props.defaultValue ?? [],
      onChange: props.onChange,
    };
  }
  const { onChange } = props;
  return {
    value: props.value !== undefined ? [props.value] : undefined,
    defaultValue: props.defaultValue !== undefined ? [props.defaultValue] : [],
    onChange: onChange ? (v: string[]) => onChange(v[0]) : undefined,
  };
}

function toggleSingle(
  prev: string[],
  value: string,
  collapsible: boolean,
): string[] {
  return prev.includes(value) ? (collapsible ? [] : prev) : [value];
}

function toggleMultiple(prev: string[], value: string): string[] {
  return prev.includes(value)
    ? prev.filter((v) => v !== value)
    : [...prev, value];
}

export function useAccordionState(props: AccordionProps) {
  const isSingle = props.type !== "multiple";
  const collapsible = props.type !== "multiple"
    ? (props.collapsible ?? true)
    : true;

  const [openValues, setOpenValues] = useControllableState(
    normalizeStateOptions(props),
  );

  const onToggle = useEffectEvent((itemValue: string) => {
    setOpenValues((prev) =>
      isSingle
        ? toggleSingle(prev, itemValue, collapsible)
        : toggleMultiple(prev, itemValue),
    );
  });

  return { openValues, onToggle, collapsible };
}

"use client";

import type {
  AnchorHTMLAttributes,
  ButtonHTMLAttributes,
  MouseEvent as ReactMouseEvent,
  ReactNode,
  Ref,
} from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { Spinner } from "../spinner/spinner";

export const buttonVariants = cva(
  "inline-flex items-center justify-center font-mono whitespace-nowrap transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background cursor-pointer",
  {
    variants: {
      variant: {
        primary:
          "bg-primary text-primary-foreground font-bold hover:bg-primary/90",
        secondary:
          "border border-border bg-transparent text-foreground hover:bg-secondary",
        destructive:
          "text-error-fg border border-error-border bg-transparent hover:bg-error-strong hover:text-error-strong-foreground",
        success:
          "bg-success-strong text-success-strong-foreground font-bold hover:bg-success-strong/90",
        ghost: "bg-transparent text-foreground hover:bg-secondary",
        outline:
          "border border-border bg-transparent text-foreground hover:bg-border",
        link: "bg-transparent text-info-fg underline-offset-2 hover:underline",
        action: "bg-action text-action-foreground font-bold hover:bg-action/90",
      },
      size: {
        sm: "h-7 px-3 text-xs",
        md: "h-9 px-4 py-2 text-sm",
        lg: "h-11 px-6 py-2 text-base",
        icon: "h-9 w-9 p-0",
      },
    },
    defaultVariants: {
      variant: "primary",
      size: "md",
    },
  },
);

type ButtonVariant = "primary" | "secondary" | "destructive" | "success" | "ghost" | "outline" | "link" | "action";
type ButtonSize = "sm" | "md" | "lg" | "icon";

interface ButtonSharedProps {
  variant?: ButtonVariant;
  size?: ButtonSize;
  bracket?: boolean;
  loading?: boolean;
  disabled?: boolean;
}

export interface ButtonAsButtonProps
  extends ButtonHTMLAttributes<HTMLButtonElement>, ButtonSharedProps {
  as?: "button";
  ref?: Ref<HTMLButtonElement>;
}

export interface ButtonAsAnchorProps
  extends AnchorHTMLAttributes<HTMLAnchorElement>, ButtonSharedProps {
  as: "a";
  ref?: Ref<HTMLAnchorElement>;
}

export type ButtonProps =
  | ButtonAsButtonProps
  | ButtonAsAnchorProps
  | ButtonRenderPropProps;

export interface ButtonRenderProps<T extends HTMLElement = HTMLElement> {
  ref?: Ref<T>;
  className: string;
  disabled?: boolean;
  "aria-busy"?: boolean;
  "aria-disabled"?: boolean;
  tabIndex?: number;
}

interface ButtonRenderPropProps<T extends HTMLElement = HTMLElement> extends ButtonSharedProps {
  className?: string;
  ref?: Ref<T>;
  as?: undefined;
  children: (props: ButtonRenderProps<T>) => ReactNode;
}

function ButtonContent({
  loading,
  bracket,
  spinnerSize,
  children,
}: {
  loading: boolean;
  bracket: boolean;
  spinnerSize: "sm" | "md" | "lg";
  children: ReactNode;
}) {
  const inner = (
    <>
      {loading && <Spinner variant="braille" size={spinnerSize} aria-hidden="true" gap="none" />}
      <span className={loading ? "sr-only" : undefined}>{children}</span>
    </>
  );
  if (bracket) {
    return (
      <>
        <span aria-hidden="true">[</span> {inner} <span aria-hidden="true">]</span>
      </>
    );
  }
  return <>{inner}</>;
}

export function Button(props: ButtonProps) {
  const {
    className,
    variant,
    size,
    bracket,
    loading = false,
    disabled,
    children,
    as: elementType,
    ...rest
  } = props;

  const isDisabled = disabled || loading;
  const resolvedClassName = cn(
    buttonVariants({ variant, size, className }),
    isDisabled && "pointer-events-none opacity-50",
  );

  if (typeof children === "function") {
    const ariaProps = {
      "aria-busy": loading || undefined,
      "aria-disabled": isDisabled || undefined,
      ...(isDisabled && { tabIndex: -1 as const }),
    };
    return children({
      ref: (props as ButtonRenderPropProps).ref,
      className: resolvedClassName,
      disabled: isDisabled || undefined,
      ...ariaProps,
    });
  }

  const spinnerSize: "sm" | "md" | "lg" =
    size === "sm" || size === "md" || size === "lg" ? size : "sm";

  if (elementType === "a") {
    const ariaProps = {
      "aria-busy": loading || undefined,
      "aria-disabled": isDisabled || undefined,
      ...(isDisabled && { tabIndex: -1 as const }),
    };
    const { ref, href, ...anchorProps } = rest as Omit<
      ButtonAsAnchorProps,
      keyof ButtonSharedProps | "children" | "className" | "as"
    >;

    return (
      <a
        className={resolvedClassName}
        ref={ref}
        href={href}
        {...ariaProps}
        {...anchorProps}
        {...(isDisabled && { onClick: (e: ReactMouseEvent) => { e.preventDefault(); } })}
      >
        <ButtonContent loading={loading} bracket={!!bracket} spinnerSize={spinnerSize}>
          {children}
        </ButtonContent>
      </a>
    );
  }

  const { ref, ...buttonProps } = rest as Omit<
    ButtonAsButtonProps,
    keyof ButtonSharedProps | "children" | "className" | "as"
  >;

  return (
    <button
      type="button"
      className={resolvedClassName}
      ref={ref}
      aria-busy={loading || undefined}
      disabled={isDisabled}
      {...buttonProps}
    >
      <ButtonContent loading={loading} bracket={!!bracket} spinnerSize={spinnerSize}>
        {children}
      </ButtonContent>
    </button>
  );
}

import { Avatar as AvatarRoot, type AvatarProps, type AvatarStatus } from "./avatar";
import { AvatarImage, type AvatarImageProps } from "./avatar-image";
import { AvatarFallback, type AvatarFallbackProps } from "./avatar-fallback";
import { AvatarGroup, type AvatarGroupProps } from "./avatar-group";
import { AvatarIndicator, type AvatarIndicatorProps } from "./avatar-indicator";

const Avatar = Object.assign(AvatarRoot, {
  Image: AvatarImage,
  Fallback: AvatarFallback,
  Group: AvatarGroup,
  Indicator: AvatarIndicator,
});

export { Avatar, type AvatarProps, type AvatarStatus };
export { AvatarImage, type AvatarImageProps };
export { AvatarFallback, type AvatarFallbackProps };
export { AvatarGroup, type AvatarGroupProps };
export { AvatarIndicator, type AvatarIndicatorProps };

"use client";

import { createContext, useContext } from "react";

export type AvatarStatus = "idle" | "loading" | "loaded" | "error";

export interface AvatarGroupContextValue {
  size?: "sm" | "md" | "lg" | null;
}

export const AvatarGroupContext = createContext<
  AvatarGroupContextValue | undefined
>(undefined);

export function useAvatarGroupContext() {
  return useContext(AvatarGroupContext);
}

export interface AvatarContextValue {
  imageStatus: AvatarStatus;
  setImageStatus: (status: AvatarStatus) => void;
}

export const AvatarContext = createContext<AvatarContextValue | undefined>(
  undefined,
);

export function useAvatarContext() {
  const ctx = useContext(AvatarContext);
  if (!ctx) {
    throw new Error(
      "Avatar.Image and Avatar.Fallback must be used within Avatar",
    );
  }
  return ctx;
}

"use client";

import {
  type HTMLAttributes,
  type ReactNode,
  type Ref,
  useEffect,
  useEffectEvent,
  useMemo,
  useState,
} from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { AvatarContext, useAvatarGroupContext, type AvatarStatus } from "./avatar-context";
import { AvatarImage } from "./avatar-image";
import { AvatarFallback } from "./avatar-fallback";

export { type AvatarStatus };

export const avatarVariants = cva(
  "relative inline-flex items-center justify-center border border-foreground/40 font-mono font-medium text-foreground bg-background overflow-hidden shrink-0",
  {
    variants: {
      size: {
        sm: "size-6 text-[10px]",
        md: "size-8 text-xs",
        lg: "size-10 text-sm",
      },
    },
    defaultVariants: { size: "md" },
  },
);

export interface AvatarProps
  extends HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof avatarVariants> {
  /** Image source URL. Ignored when children are provided. */
  src?: string;
  alt?: string;
  /** Fallback content shown when image fails. Ignored when children are provided. */
  fallback?: ReactNode;
  onStatusChange?: (status: AvatarStatus) => void;
  ref?: Ref<HTMLSpanElement>;
  children?: ReactNode;
}

function AvatarRoot({
  src,
  alt,
  fallback,
  size,
  className,
  ref,
  onStatusChange,
  children,
  ...props
}: AvatarProps) {
  const groupCtx = useAvatarGroupContext();
  const resolvedSize = size ?? groupCtx?.size;
  const [imageStatus, setImageStatus] = useState<AvatarStatus>("idle");

  const notifyStatusChange = useEffectEvent((status: AvatarStatus) => {
    onStatusChange?.(status);
  });

  useEffect(() => {
    if (imageStatus === "idle") return;
    notifyStatusChange(imageStatus);
  }, [imageStatus]);

  const contextValue = useMemo(() => ({ imageStatus, setImageStatus }), [imageStatus]);

  const label = alt ?? (typeof fallback === "string" ? fallback : undefined);

  return (
    <AvatarContext value={contextValue}>
      <span
        ref={ref}
        role={label ? "img" : "presentation"}
        aria-label={label || undefined}
        className={cn(avatarVariants({ size: resolvedSize }), className)}
        {...props}
      >
        {children ?? (
          <>
            {src && <AvatarImage src={src} />}
            <AvatarFallback>{fallback ?? "?"}</AvatarFallback>
          </>
        )}
      </span>
    </AvatarContext>
  );
}

export { AvatarRoot as Avatar };

"use client";

import { useEffect, type ImgHTMLAttributes, type Ref } from "react";
import { cn } from "@/lib/utils";
import { useAvatarContext } from "./avatar-context";
import { useImageStatus } from "./use-image-status";

export interface AvatarImageProps
  extends Omit<ImgHTMLAttributes<HTMLImageElement>, "alt"> {
  alt?: string;
  ref?: Ref<HTMLImageElement>;
}

export function AvatarImage({
  src,
  alt,
  className,
  ref,
  ...imgProps
}: AvatarImageProps) {
  const { setImageStatus } = useAvatarContext();
  const { status, showImage, onLoad, onError } = useImageStatus(src);

  useEffect(() => {
    setImageStatus(status);
    return () => setImageStatus("idle");
  }, [status, setImageStatus]);

  if (!showImage) return null;

  return (
    <img
      ref={ref}
      src={src}
      alt={alt ?? ""}
      onLoad={onLoad}
      onError={onError}
      className={cn("absolute inset-0 size-full object-cover", className)}
      {...imgProps}
    />
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAvatarContext } from "./avatar-context";
import { useImageStatus } from "./use-image-status";

export interface AvatarFallbackProps {
  /** Cascading fallback image URL. Tried before rendering children. */
  src?: string;
  children?: ReactNode;
  className?: string;
}

function CascadingImage({ src, className }: { src: string; className?: string }) {
  const { showImage, onLoad, onError } = useImageStatus(src);
  if (!showImage) return null;
  return (
    <img
      src={src}
      alt=""
      onLoad={onLoad}
      onError={onError}
      className={cn("absolute inset-0 size-full object-cover", className)}
    />
  );
}

export function AvatarFallback({
  src,
  children,
  className,
}: AvatarFallbackProps) {
  const { imageStatus } = useAvatarContext();

  if (imageStatus === "loaded") return null;
  if (src) return <CascadingImage src={src} className={className} />;

  return (
    <span aria-hidden="true" className={className}>
      {children}
    </span>
  );
}

"use client";

import { type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { avatarVariants } from "./avatar";
import { useAvatarGroupContext } from "./avatar-context";

export interface AvatarIndicatorProps extends VariantProps<typeof avatarVariants> {
  count: number;
  className?: string;
}

export function AvatarIndicator({ count, size, className }: AvatarIndicatorProps) {
  const groupCtx = useAvatarGroupContext();
  const resolvedSize = size ?? groupCtx?.size;
  return (
    <span
      role="img"
      aria-label={`${count} more`}
      className={cn(avatarVariants({ size: resolvedSize }), "border-dashed bg-muted text-foreground", className)}
    >
      <span aria-hidden="true">+{count}</span>
    </span>
  );
}

"use client";

import { Children, useMemo, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { AvatarGroupContext } from "./avatar-context";
import { AvatarIndicator } from "./avatar-indicator";
import { Overflow } from "../overflow/overflow";

export interface AvatarGroupProps {
  max?: number;
  /** How avatars are spaced. "overlap" (default) stacks them, "gap" adds spacing between. */
  spacing?: "overlap" | "gap";
  children: ReactNode;
  size?: "sm" | "md" | "lg" | null;
  className?: string;
  "aria-label"?: string;
}

const spacingClasses = {
  overlap: "-space-x-1.5",
  gap: "gap-1",
} satisfies Record<string, string>;

export function AvatarGroup({ max, spacing = "overlap", children, size = "md", className, "aria-label": ariaLabel = "Avatars" }: AvatarGroupProps) {
  const allItems = Children.toArray(children);
  const groupContextValue = useMemo(() => ({ size }), [size]);

  if (max != null) {
    const visibleItems = allItems.slice(0, max);
    const overflowCount = allItems.length - max;

    return (
      <AvatarGroupContext value={groupContextValue}>
        <div role="group" aria-label={ariaLabel} className={cn("flex w-fit items-center", spacingClasses[spacing], className)}>
          {visibleItems}
          {overflowCount > 0 && <AvatarIndicator count={overflowCount} />}
        </div>
      </AvatarGroupContext>
    );
  }

  return (
    <AvatarGroupContext value={groupContextValue}>
      <div role="group" aria-label={ariaLabel}>
        <Overflow
          mode="items"
          gap={spacingClasses[spacing]}
          className={className}
          indicator={({ count }) => <AvatarIndicator count={count} />}
        >
          {allItems}
        </Overflow>
      </div>
    </AvatarGroupContext>
  );
}

"use client";
import { useState } from "react";
import type { AvatarStatus } from "./avatar-context";

export function useImageStatus(src: string | undefined) {
  const [status, setStatus] = useState<AvatarStatus>(src ? "loading" : "idle");

  const [prevSrc, setPrevSrc] = useState(src);
  if (src !== prevSrc) {
    setPrevSrc(src);
    setStatus(src ? "loading" : "idle");
  }

  return {
    status,
    showImage: !!src && status !== "error",
    onLoad: () => setStatus("loaded"),
