}

const variantRole: Record<CalloutVariant, string | undefined> = {
  info: undefined,
  warning: "status",
  error: "alert",
  success: "status",
};

export function Callout({
  className,
  variant = "info",
  visible: controlledVisible,
  defaultVisible,
  onVisibleChange,
