}

export function SearchInput({
  value,
  defaultValue,
  onChange,
  onEscape,
  onEnter,
  onKeyDown,
  placeholder = "Search...",
  prefix = defaultPrefix,
  className,
  ref,
  size,
  error,
  disabled,
  "aria-label": ariaLabel,
  ...rest
}: SearchInputProps) {
  const [current, setValue] = useControllableState({
    value,
    defaultValue: defaultValue ?? "",
    onChange,
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Escape") {
      e.preventDefault();
      onEscape?.();
