      e.preventDefault();
      onEnter();
    }
    onKeyDown?.(e);
  };

  return (
    <search
      className={cn(
        searchInputVariants({ size, error, disabled }),
        className,
      )}
    >
      {prefix}
      <input
        ref={ref}
        type="search"
