function SidebarNav({ ref, className, ...rest }: HTMLAttributes<HTMLElement> & { ref?: Ref<HTMLElement> }) {
  return (
    <nav ref={ref} aria-label="Sidebar" {...rest} className={cn("flex flex-col h-full", className)} />
