export { computeDiff } from "./compute.js";
export { resolveDiffInput } from "./resolve.js";
export { computeWordSegments, annotateWordDiff } from "./word.js";
export { toSplitRows } from "./split.js";
export type { ParsedDiff, DiffHunk, DiffChange, ChangeType, DiffInput, DiffInputPatch, DiffInputCompare, DiffInputParsed } from "./parse.js";
export type { WordSegment, AnnotatedChange } from "./word.js";
export type { SplitCell, SplitRow } from "./split.js";

export type ChangeType = "add" | "remove" | "context";

export interface DiffChange {
  type: ChangeType;
  content: string;
  oldLine: number | null;
  newLine: number | null;
}

/** UI-oriented hunk for single-file rendering. @see diffgazer/apps/server/src/shared/lib/diff/types.ts for the server-side multi-file variant. */
export interface DiffHunk {
  oldStart: number;
  oldCount: number;
  newStart: number;
  newCount: number;
  heading: string;
  changes: DiffChange[];
}

/** UI-oriented parsed diff (single-file). @see diffgazer/apps/server/src/shared/lib/diff/types.ts for the server-side multi-file variant. */
export interface ParsedDiff {
  oldPath: string | null;
  newPath: string | null;
  hunks: DiffHunk[];
}

export interface DiffInputPatch { patch: string; diff?: never; before?: never; after?: never; }
export interface DiffInputCompare { before: string; after: string; patch?: never; diff?: never; }
export interface DiffInputParsed { diff: ParsedDiff; patch?: never; before?: never; after?: never; }
export type DiffInput = DiffInputPatch | DiffInputCompare | DiffInputParsed;

const HUNK_RE = /^@@\s+-(\d+)(?:,(\d+))?\s+\+(\d+)(?:,(\d+))?\s+@@(.*)$/;

const SKIP_RE = /^(index |new file mode|deleted file mode|old mode|new mode|similarity index|rename from|rename to|Binary files|copy from|copy to)/;

export function parseDiff(patch: string): ParsedDiff[] {
  const lines = patch.split("\n");
  const files: ParsedDiff[] = [];
  let current: ParsedDiff | null = null;
  let hunk: DiffHunk | null = null;
  let oldLine = 0;
  let newLine = 0;

  for (const line of lines) {
    if (line.startsWith("diff --git ")) {
      if (current) files.push(current);
      current = { oldPath: null, newPath: null, hunks: [] };
      hunk = null;
      continue;
    }

    if (SKIP_RE.test(line)) continue;

    if (line.startsWith("--- ")) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      current.oldPath = line.replace(/^---\s+(?:a\/)?/, "");
      continue;
    }
    if (line.startsWith("+++ ")) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      current.newPath = line.replace(/^\+\+\+\s+(?:b\/)?/, "");
      continue;
    }

    const m = HUNK_RE.exec(line);
    if (m) {
      if (!current) current = { oldPath: null, newPath: null, hunks: [] };
      hunk = {
        oldStart: Number(m[1]),
        oldCount: Number(m[2] ?? 1),
        newStart: Number(m[3]),
        newCount: Number(m[4] ?? 1),
        heading: m[5].trim(),
        changes: [],
      };
      current.hunks.push(hunk);
      oldLine = hunk.oldStart;
      newLine = hunk.newStart;
      continue;
    }

    if (!hunk) continue;
    if (line.startsWith("\\")) continue;

    if (line.startsWith("-")) {
      hunk.changes.push({ type: "remove", content: line.slice(1), oldLine, newLine: null });
      oldLine++;
    } else if (line.startsWith("+")) {
      hunk.changes.push({ type: "add", content: line.slice(1), oldLine: null, newLine });
      newLine++;
    } else {
      const content = line.startsWith(" ") ? line.slice(1) : line;
      hunk.changes.push({ type: "context", content, oldLine, newLine });
      oldLine++;
      newLine++;
    }
  }

  if (current) files.push(current);

  return files;
}

import type { DiffChange, DiffHunk, ParsedDiff } from "./parse.js";
import { buildLcsTable } from "./lcs.js";

const CONTEXT = 3;

export function computeDiff(before: string, after: string): ParsedDiff {
  const oldLines = before.split("\n");
  const newLines = after.split("\n");
  const edits = lcsEdits(oldLines, newLines);
  return { oldPath: null, newPath: null, hunks: groupHunks(edits) };
}

function naiveEdits(oldLines: string[], newLines: string[]): DiffChange[] {
  const edits: DiffChange[] = [];
  for (let i = 0; i < oldLines.length; i++) {
    edits.push({ type: "remove", content: oldLines[i], oldLine: i + 1, newLine: null });
  }
  for (let j = 0; j < newLines.length; j++) {
    edits.push({ type: "add", content: newLines[j], oldLine: null, newLine: j + 1 });
  }
  return edits;
}

function lcsEdits(oldLines: string[], newLines: string[]): DiffChange[] {
  const dp = buildLcsTable(oldLines, newLines);
  if (!dp) return naiveEdits(oldLines, newLines);

  const m = oldLines.length;
  const n = newLines.length;

  const edits: DiffChange[] = [];
  let i = m;
  let j = n;
  while (i > 0 || j > 0) {
    if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
      edits.push({ type: "context", content: oldLines[i - 1], oldLine: i, newLine: j });
      i--;
      j--;
    } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
      edits.push({ type: "add", content: newLines[j - 1], oldLine: null, newLine: j });
      j--;
    } else {
      edits.push({ type: "remove", content: oldLines[i - 1], oldLine: i, newLine: null });
      i--;
    }
  }
  edits.reverse();
  return edits;
}

function findChangeIndices(edits: DiffChange[]): number[] {
  const indices: number[] = [];
  for (let i = 0; i < edits.length; i++) {
    if (edits[i].type !== "context") indices.push(i);
  }
  return indices;
}

function mergeNearbyRanges(indices: number[], gap: number): [number, number][] {
  const ranges: [number, number][] = [];
  let start = indices[0];
  let end = indices[0];
  for (let k = 1; k < indices.length; k++) {
    if (indices[k] - end <= gap) {
      end = indices[k];
    } else {
      ranges.push([start, end]);
      start = indices[k];
      end = indices[k];
    }
  }
  ranges.push([start, end]);
  return ranges;
}

function buildHunk(edits: DiffChange[], range: [number, number], context: number): DiffHunk {
  const from = Math.max(0, range[0] - context);
  const to = Math.min(edits.length - 1, range[1] + context);
  const changes = edits.slice(from, to + 1);

  const firstOld = changes.find((e) => e.oldLine != null);
  const firstNew = changes.find((e) => e.newLine != null);

  let oldCount = 0;
  let newCount = 0;
  for (const e of changes) {
    if (e.type !== "add") oldCount++;
    if (e.type !== "remove") newCount++;
  }

  return {
    oldStart: firstOld?.oldLine ?? 1,
    oldCount,
    newStart: firstNew?.newLine ?? 1,
    newCount,
    heading: "",
    changes,
  };
}

function groupHunks(edits: DiffChange[]): DiffHunk[] {
  const indices = findChangeIndices(edits);
  if (indices.length === 0) return [];
  const ranges = mergeNearbyRanges(indices, CONTEXT * 2 + 1);
  return ranges.map((range) => buildHunk(edits, range, CONTEXT));
}

import type { DiffChange } from "./parse.js";
import { buildLcsTable } from "./lcs.js";
import { collectEditPairs } from "./pairs.js";

export interface WordSegment {
  text: string;
  changed: boolean;
}

export interface AnnotatedChange extends DiffChange {
  wordSegments?: WordSegment[];
}

export function computeWordSegments(oldContent: string, newContent: string): { old: WordSegment[]; new: WordSegment[] } {
  const oldWords = oldContent.split(/(\s+)/);
  const newWords = newContent.split(/(\s+)/);
  const dp = buildLcsTable(oldWords, newWords);

  if (!dp) {
    return {
      old: [{ text: oldContent, changed: true }],
      new: [{ text: newContent, changed: true }],
    };
  }

  const m = oldWords.length;
  const n = newWords.length;

  const oldSegs: WordSegment[] = [];
  const newSegs: WordSegment[] = [];
  let i = m;
  let j = n;

  while (i > 0 || j > 0) {
    if (i > 0 && j > 0 && oldWords[i - 1] === newWords[j - 1]) {
      oldSegs.push({ text: oldWords[i - 1], changed: false });
      newSegs.push({ text: newWords[j - 1], changed: false });
      i--; j--;
    } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
      newSegs.push({ text: newWords[j - 1], changed: true });
      j--;
    } else {
      oldSegs.push({ text: oldWords[i - 1], changed: true });
      i--;
    }
  }

  oldSegs.reverse();
  newSegs.reverse();

  return { old: mergeSegments(oldSegs), new: mergeSegments(newSegs) };
}

function mergeSegments(segments: WordSegment[]): WordSegment[] {
  const result: WordSegment[] = [];
  for (const seg of segments) {
    const last = result[result.length - 1];
    if (last && last.changed === seg.changed) {
      last.text += seg.text;
    } else {
      result.push({ text: seg.text, changed: seg.changed });
    }
  }
  return result;
}

export function annotateWordDiff(changes: DiffChange[]): AnnotatedChange[] {
  const result: AnnotatedChange[] = [];

  for (const item of collectEditPairs(changes)) {
    if ("type" in item) {
      result.push(item);
      continue;
    }

    const { removes, adds } = item;
    const pairs = Math.min(removes.length, adds.length);

    const segmentPairs = [];
    for (let j = 0; j < pairs; j++) {
      segmentPairs.push(computeWordSegments(removes[j].content, adds[j].content));
    }

    for (let j = 0; j < pairs; j++) {
      result.push({ ...removes[j], wordSegments: segmentPairs[j].old });
    }
    for (let j = pairs; j < removes.length; j++) result.push(removes[j]);

    for (let j = 0; j < pairs; j++) {
      result.push({ ...adds[j], wordSegments: segmentPairs[j].new });
    }
    for (let j = pairs; j < adds.length; j++) result.push(adds[j]);
  }

  return result;
}

import type { DiffHunk, ChangeType } from "./parse.js";
import { computeWordSegments, type WordSegment } from "./word.js";
import { collectEditPairs } from "./pairs.js";

export interface SplitCell {
  type: ChangeType | "empty";
  content: string;
  lineNumber: number | null;
  wordSegments?: WordSegment[];
}

export type SplitRow =
  | { kind: "change"; left: SplitCell; right: SplitCell }
  | { kind: "separator"; oldStart: number; oldCount: number; newStart: number; newCount: number; heading: string };

export function toSplitRows(hunks: DiffHunk[], wordDiff: boolean): SplitRow[] {
  const rows: SplitRow[] = [];

  for (const hunk of hunks) {
    rows.push({
      kind: "separator",
      oldStart: hunk.oldStart,
      oldCount: hunk.oldCount,
      newStart: hunk.newStart,
      newCount: hunk.newCount,
      heading: hunk.heading,
    });

    for (const item of collectEditPairs(hunk.changes)) {
      if ("type" in item) {
        rows.push({
          kind: "change",
          left: { type: "context", content: item.content, lineNumber: item.oldLine },
          right: { type: "context", content: item.content, lineNumber: item.newLine },
        });
        continue;
      }

      const { removes, adds } = item;
      const pairs = Math.max(removes.length, adds.length);

      for (let j = 0; j < pairs; j++) {
        let leftSegs: WordSegment[] | undefined;
        let rightSegs: WordSegment[] | undefined;

        if (wordDiff && j < removes.length && j < adds.length) {
          const { old: oSegs, new: nSegs } = computeWordSegments(removes[j].content, adds[j].content);
          leftSegs = oSegs;
          rightSegs = nSegs;
        }

        rows.push({
          kind: "change",
          left: j < removes.length
            ? { type: "remove", content: removes[j].content, lineNumber: removes[j].oldLine, wordSegments: leftSegs }
            : { type: "empty", content: "", lineNumber: null },
          right: j < adds.length
            ? { type: "add", content: adds[j].content, lineNumber: adds[j].newLine, wordSegments: rightSegs }
            : { type: "empty", content: "", lineNumber: null },
        });
      }
    }
  }

  return rows;
}

const MAX_LCS_SIZE = 5_000;

export function buildLcsTable(a: string[], b: string[]): number[][] | null {
  if (a.length > MAX_LCS_SIZE || b.length > MAX_LCS_SIZE) {
    return null;
  }

  const m = a.length;
  const n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => new Array<number>(n + 1).fill(0));
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1] + 1
        : Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }
  return dp;
}

import type { DiffChange } from "./parse.js";

export interface EditPairGroup {
  removes: DiffChange[];
  adds: DiffChange[];
}

export function* collectEditPairs(
  changes: DiffChange[],
): Generator<DiffChange | EditPairGroup> {
  let i = 0;
  while (i < changes.length) {
    if (changes[i].type === "context") {
      yield changes[i];
      i++;
      continue;
    }
    const removes: DiffChange[] = [];
    while (i < changes.length && changes[i].type === "remove")
      removes.push(changes[i++]);
    const adds: DiffChange[] = [];
    while (i < changes.length && changes[i].type === "add")
      adds.push(changes[i++]);
    yield { removes, adds };
  }
}

import type { ParsedDiff, DiffInput } from "./parse.js";
import { parseDiff } from "./parse.js";
import { computeDiff } from "./compute.js";

const EMPTY: ParsedDiff = { oldPath: null, newPath: null, hunks: [] };

export function resolveDiffInput(input: DiffInput): ParsedDiff {
  if ("diff" in input && input.diff != null) return input.diff;
  if ("patch" in input && input.patch != null) return parseDiff(input.patch)[0] ?? EMPTY;
  if ("before" in input && input.before != null && "after" in input && input.after != null) {
    return computeDiff(input.before, input.after);
  }
  return EMPTY;
}

import type { RefObject, Ref, RefCallback } from "react";

export function composeRefs<T>(
  ...refs: Array<Ref<T> | null | undefined>
): RefCallback<T> {
  return (element: T | null) => {
    for (const ref of refs) {
      if (typeof ref === "function") {
        ref(element);
      } else if (ref != null) {
        (ref as RefObject<T | null>).current = element;
      }
    }
  };
}

export function resolveTabTarget(
  isActive: boolean,
  hasSelection: boolean,
  container: HTMLElement | null,
  value: string,
  role: string = "radio",
): boolean {
  if (isActive) return true;
  if (hasSelection) return false;
  if (!container) return true;
  const first = container.querySelector(`[role="${role}"]:not(:disabled):not([aria-disabled="true"])`);
  return first?.getAttribute("data-value") === value;
}

